SELECT
id, number, name, abbreviation, nation, region, address, legal_person AS legalPerson,
establish_date AS establishDate, foreign_share AS foreignShare, manager, supplier_category AS supplierCategory,
supply_type AS supplyType, supplier_group AS supplierGroup, main_product AS mainProduct, business_registration AS businessRegistration, social_credit_code AS socialCreditCode,
source, business_license AS businessLicense, invoice_name AS invoiceName, customization, turnover, factory_people AS factoryPeople, behave, contact_info AS contactInfo, follow_up_feedback AS followUpFeedback,
settlement_currency AS settlementCurrency, factory_positioning AS factoryPositioning, quality_control AS qualityControl, factory_equipment AS factoryEquipment, factory_area AS factoryArea, factory_certification AS factoryCertification, export_market AS exportMarket, settlement_method AS settlementMethod, payment_terms AS paymentTerms, invoice_type AS invoiceType,
tax_category AS taxCategory, settlement_party AS settlementParty, payee, default_tax_rate AS defaultTaxRate, created_by AS createdBy, created_at AS createdAt,
updated_by AS updatedBy, updated_at AS updatedAt, auditor, audit_time AS auditTime
FROM supplier

    AND number = #{number}
    AND name LIKE CONCAT('%', #{name}, '%')
    AND abbreviation LIKE CONCAT('%', #{abbreviation}, '%')
    AND region = #{region}
    AND address LIKE CONCAT('%', #{address}, '%')
    AND legal_person = #{legalPerson}
    AND establish_date = #{establishDate}
    AND foreign_share = #{foreignShare}
    AND manager = #{manager}
    AND supplier_category = #{supplierCategory}
    AND supply_type = #{supplyType}
    AND supplier_group = #{supplierGroup}
    AND main_product LIKE CONCAT('%', #{mainProduct}, '%')
    AND business_registration = #{businessRegistration}
    AND social_credit_code = #{socialCreditCode}
    AND source = #{source}
    AND invoice_name = #{invoiceName}
    AND customization = #{customization}
    AND turnover = #{turnover}
    AND factory_people = #{factoryPeople}
    AND behave = #{behave}
    AND contact_info = #{contactInfo}
    AND follow_up_feedback = #{followUpFeedback}
    AND settlement_currency = #{settlementCurrency}
    AND factory_positioning = #{factoryPositioning}
    AND quality_control = #{qualityControl}
    AND factory_equipment = #{factoryEquipment}
    AND factory_area = #{factoryArea}
    AND factory_certification = #{factoryCertification}
    AND export_market = #{exportMarket}
    AND payment_terms = #{paymentTerms}
    AND invoice_type = #{invoiceType}
    AND tax_category = #{taxCategory}
    AND settlement_party = #{settlementParty}
    AND default_tax_rate = #{defaultTaxRate}
    AND supplierid = #{supplierid}

ORDER BY created_at DESC

SELECT
    number
FROM supplier
WHERE supplier_group = #{supplierGroup}
ORDER BY created_at DESC LIMIT 1;
